function [rDir,clbDir,scnDir,anlDir] = fDnnRootDir(day,mode)%% Returns root and calibration directory for DNN experiments% function DNN Root Directory%% [rDir,clbDir,scnDir,anlDir] = fBellaRootDirV01(day,mode)%% day: day string such as '13_0311'.% mode: 1: server, 2:local% rDir: root directory% clbDir: magspec calibration directory%% Written by Kei Nakamura% 2018/2/8 ver.1: inherited from fBellaRootDir%%% main bodymonthSC{1} = [filesep '01-Jan' filesep];monthSC{2} = [filesep '02-Feb' filesep];monthSC{3} = [filesep '03-Mar' filesep];monthSC{4} = [filesep '04-Apr' filesep];monthSC{5} = [filesep '05-May' filesep];monthSC{6} = [filesep '06-Jun' filesep];monthSC{7} = [filesep '07-Jul' filesep];monthSC{8} = [filesep '08-Aug' filesep];monthSC{9} = [filesep '09-Sep' filesep];monthSC{10} = [filesep '10-Oct' filesep];monthSC{11} = [filesep '11-Nov' filesep];monthSC{12} = [filesep '12-Dec' filesep];if ismac    %rrDir = [filesep 'Volumes' filesep 'vol1'];    rrDir = [filesep 'Volumes' filesep 'hdna2'];else    rrDir = ['Z:'];endif mode==1    year = day(1:2);    yearD = ['Y20',year];    month = day(4:5);    monthD = monthSC{str2num(month)};    rDir = [rrDir filesep 'data' filesep 'Thomson' filesep yearD monthD day];    %rDir = [filesep 'Volumes' filesep 'belladata' filesep 'data' filesep 'p2' filesep yearD monthD day];    clbDir = [rrDir filesep 'data' filesep 'Thomson' filesep 'Calibrations'];else    %clbDir = [filesep 'Users' filesep 'kee' filesep 'Documents' filesep 'data' filesep 'BELLA' filesep 'magspecCalib'];    clbDir = '/Users/kee/Dropbox (Bella Center)/Documents/data/DNNMoore/calibrations';    rDir = ['/Users/kee/Dropbox (Bella Center)/Documents/data/DNNMoore/',day,'*'];    list = dir(rDir);    rDir = ['/Users/kee/Dropbox (Bella Center)/Documents/data/DNNMoore',filesep,list.name];    %rDir = [list.folder,filesep,list.name];endanlDir = [rDir,filesep,'analysis'];        % analysis directoryscnDir = [rDir filesep 'scans'];           % scan directory
